    const MOD = 10**9 + 7;
    const map = new Map();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!map.has(y)) {
            map.set(y, []);
        }
        map.get(y).push(x);
    }

    // Count the number of horizontal lines (same y-coordinate)
    let horizontalLines = 0;
    for (const y of map.keys()) {
        const xs = map.get(y);
        if (xs.length >= 2) {
            horizontalLines += (xs.length * (xs.length - 1)) / 2;
