function solve(points) {
    const MOD = 10**9 + 7;
    const map = new Map();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!map.has(y)) {
            map.set(y, []);
        }
        map.get(y).push(x);
    }

    // Count the number of horizontal lines (same y-coordinate)
    let horizontalLines = 0;
    for (const y of map.keys()) {
        const xs = map.get(y);
        if (xs.length >= 2) {
            horizontalLines += (xs.length * (xs.length - 1)) / 2;
        }
    }

    // Count the number of horizontal trapezoids
    let count = 0;

    // For each pair of horizontal lines
    const yList = Array.from(map.keys());
    for (let i = 0; i < yList.length; i++) {
        for (let j = i + 1; j < yList.length; j++) {
            const y1 = yList[i];
            const y2 = yList[j];
            const xs1 = map.get(y1);
            const xs2 = map.get(y2);

            // Count the number of pairs of points on the first line
            let pairs1 = 0;
            for (let k = 0; k < xs1.length; k++) {
                for (let l = k + 1; l < xs1.length; l++) {
                    pairs1++;
                }
            }

            // Count the number of pairs of points on the second line
            let pairs2 = 0;
            for (let k = 0; k < xs2.length; k++) {
                for (let l = k + 1; l < xs2.length; l++) {
                    pairs2++;
                }
            }

            // Add the number of trapezoids formed by these pairs
            count += pairs1 * pairs2;
            count %= MOD;
        }
    }

    return count;
}

